from typing import List
from math import gcd

class Solution:
    def minimumArrayLength(self, nums: List[int]) -> int:
        g = 0
        for x in nums:
            g = gcd(g, x)
        # Min achievable length equals the number of array elements whose value is gcd(nums)
        # (equivalently, gcd is the only value that can remain non-zero; others can be reduced away)
        return sum(1 for x in nums if x == g)
```

